   736→            }
   737→          }
   738→          setTimeout(() => {
   739→            setOutfitAnimation("none");
   740→            advanceOrEnd();
   741→          }, 800);
   742→        } else if (gestureType === "thumbs_down") {
   743→          setOutfitAnimation("dislike-dismiss");
   744→          setTimeout(() => {
   745→            setOutfitAnimation("none");
   746→            advanceOrEnd();
   747→          }, 700);
   748→        }
   749→      }
   750→    };
   751→
   752→    holdRafRef.current = requestAnimationFrame(tick);
   753→    return () => cancelAnimationFrame(holdRafRef.current);
