  1175→        <div
  1176→          style={{
  1177→            position: "absolute",
  1178→            bottom: 20,
  1179→            right: 20,
  1180→            padding: "8px 12px",
  1181→            background: "rgba(0,0,0,0.7)",
  1182→            borderRadius: 8,
  1183→            color: "#fff",
  1184→            fontSize: "0.75rem",
  1185→            zIndex: 30,
  1186→            fontFamily: "monospace",
  1187→          }}
  1188→        >
  1189→          {Array.from(fitStatuses.entries()).map(([id, method]) => (
  1190→            <div key={id}>
  1191→              {id.slice(0, 8)}: {method === "precise" ? "anchor" : "quad"}
  1192→            </div>
  1193→          ))}
  1194→        </div>
  1195→      )}
  1196→    </main>
  1197→  );
  1198→}
